export type Producto = {
  id: number;
  nombre: string;
  categoria: string;
  precio: number;
  descripcion?: string;
};

const API_BASE_URL = "http://localhost:8080/api";

export async function getMenu(): Promise<Producto[]> {
  console.log("🔄 Cargando menú desde:", `${API_BASE_URL}/menu`); // Debug log

  try {
    const res = await fetch(`${API_BASE_URL}/menu`);
    console.log("📡 Respuesta del servidor:", res.status, res.statusText); // Debug log

    if (!res.ok) {
      throw new Error(`Error HTTP: ${res.status} - ${res.statusText}`);
    }

    const data = await res.json();
    console.log("✅ Productos cargados desde backend:", data.length); // Debug log
    console.log("📋 Productos:", data); // Debug log

    return data;
  } catch (error) {
    console.error("❌ Error al cargar menú desde backend:", error); // Debug log
    console.log("🔄 Usando datos mock como fallback"); // Debug log

    // Mock data para desarrollo
    const mockData = [
      {
        id: 1,
        nombre: "Pizza Margherita",
        categoria: "PLATOS_PRINCIPALES",
        precio: 15.99,
      },
      { id: 2, nombre: "Ensalada César", categoria: "ENTRADAS", precio: 8.5 },
      { id: 3, nombre: "Tiramisu", categoria: "POSTRES", precio: 6.99 },
    ];

    console.log("📋 Datos mock:", mockData); // Debug log
    return mockData;
  }
}

export async function agregarProducto(
  producto: Omit<Producto, "id">
): Promise<Producto> {
  console.log("➕ Agregando producto:", producto); // Debug log

  try {
    const res = await fetch(`${API_BASE_URL}/menu`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Accept: "application/json",
      },
      body: JSON.stringify(producto),
    });

    if (!res.ok) {
      const errorText = await res.text();
      throw new Error(`Error HTTP: ${res.status} - ${errorText}`);
    }

    const data = await res.json();
    console.log("✅ Producto agregado:", data); // Debug log
    return data;
  } catch (error) {
    console.error("❌ Error al agregar producto:", error); // Debug log
    // Mock para desarrollo
    const mockProduct = { ...producto, id: Date.now() };
    console.log("🔄 Producto mock creado:", mockProduct); // Debug log
    return mockProduct;
  }
}

export async function eliminarProducto(id: number): Promise<void> {
  console.log("🗑️ Eliminando producto ID:", id); // Debug log

  try {
    const res = await fetch(`${API_BASE_URL}/menu/${id}`, {
      method: "DELETE",
    });

    if (!res.ok) {
      throw new Error(`Error HTTP: ${res.status}`);
    }

    console.log("✅ Producto eliminado exitosamente"); // Debug log
  } catch (error) {
    console.error("❌ Error al eliminar producto:", error); // Debug log
    throw error;
  }
}

export async function editarProducto(
  id: number,
  producto: Partial<Omit<Producto, "id">>
): Promise<Producto> {
  console.log("✏️ Editando producto ID:", id, producto); // Debug log

  try {
    const res = await fetch(`${API_BASE_URL}/menu/${id}`, {
      method: "PUT",
      headers: {
        "Content-Type": "application/json",
        Accept: "application/json",
      },
      body: JSON.stringify(producto),
    });

    if (!res.ok) {
      const errorText = await res.text();
      throw new Error(`Error HTTP: ${res.status} - ${errorText}`);
    }

    const data = await res.json();
    console.log("✅ Producto editado:", data); // Debug log
    return data;
  } catch (error) {
    console.error("❌ Error al editar producto:", error); // Debug log
    throw error;
  }
}
